// §268. Channel selection is config-driven (config/admin.config.yaml ->
// notifications.channels). v1 supports 'email'. 'slack'/'teams' are declared
// but marked future: if selected, they route to a no-op-with-log path so the
// workflow never silently drops a notification (§269 handle errors).
const cfg = $vars.CRIE_NOTIFY_CHANNELS ? JSON.parse($vars.CRIE_NOTIFY_CHANNELS) : { active: ['email'] };
const active = cfg.active || ['email'];
const j = $json;
return active.map(ch => ({ json: { ...j, channel: ch, supported: ch === 'email' } }));
